const raw = $input.first().json;
const outputText = (raw.output ?? JSON.stringify(raw)).trim();

// Parse agent output — strip markdown fences if present
let parsed;
try {
  const clean = outputText.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '');
  parsed = JSON.parse(clean);
  if (Array.isArray(parsed)) parsed = parsed[0] ?? parsed;
} catch {
  return [{ json: { output: outputText, parse_error: true } }];
}

const fields = parsed.fields ?? {};

// Risk weights mirror contract_playbook.risk_weight
const RISK_WEIGHTS = {
  commencement_date: 10, expiry_date: 10, annual_payment: 10, discount_rate: 10,
  renewal_options: 8, termination_rights: 8, escalation_rate: 7,
  rou_asset_scope: 6, security_deposit: 5, governing_law: 3,
};

const isMissing = (f) => !f || f.value === null || f.value === undefined || f.value === '';

const terms_found = Object.keys(fields).filter(k => !isMissing(fields[k]));
const terms_missing = Object.keys(fields).filter(k => isMissing(fields[k]));

// Risk score: start at 100, deduct weight for each missing field
let risk_score = 100;
for (const key of terms_missing) risk_score -= (RISK_WEIGHTS[key] ?? 3);
risk_score = Math.max(0, Math.min(100, risk_score));

// Risk flag rules for high-priority missing fields
const FLAG_RULES = {
  discount_rate: {
    id: 'missing_discount_rate', severity: 'high',
    title: 'Discount rate missing',
    description: 'IFRS 16 requires a discount rate to calculate present value of lease payments and the ROU asset. The contract does not specify one — enter your IBR manually before finalising the report.',
    ifrs16_ref: '§26',
  },
  renewal_options: {
    id: 'renewal_certainty', severity: 'medium',
    title: 'Renewal options — certainty not assessed',
    description: 'IFRS 16 §19 requires assessment of whether renewal options are reasonably certain to be exercised. Document intent language for auditors.',
    ifrs16_ref: '§19',
  },
  termination_rights: {
    id: 'termination_rights', severity: 'medium',
    title: 'Termination rights — non-cancellable period unclear',
    description: 'IFRS 16.B34 requires the non-cancellable period to be confirmed. Verify termination conditions and document the effective lease term.',
    ifrs16_ref: 'B34',
  },
  security_deposit: {
    id: 'security_deposit_classification', severity: 'low',
    title: 'Security deposit — classification unclear',
    description: 'The security deposit may need to be classified as a lease incentive receivable depending on refund terms. Verify refund conditions in the lease schedule.',
    ifrs16_ref: '§46',
  },
};

const risk_flags = [];
for (const [key, rule] of Object.entries(FLAG_RULES)) {
  if (isMissing(fields[key])) risk_flags.push({ ...rule, field: key });
}

return [{
  json: {
    contract_type: parsed.contract_type ?? 'LEASE',
    terms_found,
    terms_missing,
    risk_score,
    analyzed_at: new Date().toISOString(),
    fields,
    risk_flags,
  }
}];
